class Solution:
    def solve(self, edges: List[List[int]]) -> int:
        n = len(edges)
        if n == 0:
            return -1

        graph = {}  # initialize an adjacency list
        for i in range(n):
            graph[i] = []
        for i in range(n):
            for j in edges[i]:
                graph[i].append(j)
        visited = [0] * n
        dist = [0] * n
        for i in range(n):
            if visited[i] == 0:
                self.dfs(i, graph, visited, dist)
                if self.is_cycle(visited, n):
                    return dist[i]
        return -1

    def dfs(self, node, graph, visited, dist):
        visited[node] = 1
        for child in graph[node]:
            if visited[child] == 0:
                dist[child] = dist[node] + 1
                self.dfs(child, graph, visited, dist)
            elif visited[child] == 1:
                if dist[node] + 1 > dist[child]:
                    dist[child] = dist[node] + 1

    def is_cycle(self, visited, n):
        for i in range(n):
            if visited[i] != 2:
                return False
        return True

