class Solution {
public:
    int solve(vector<vector<int>>& edges) {
        int n = edges.size();
        if (n == 0) return -1;

        vector<vector<int>> graph(n);
        for (int i = 0; i < n; i++) graph[i] = {};
        for (int i = 0; i < n; i++) {
            for (int j : edges[i]) {
                graph[i].push_back(j);
            }
        }
        int visited[n];
        int dist[n];
        for (int i = 0; i < n; i++) {
            if (visited[i] == 0) {
                dfs(i, graph, visited, dist);
                if (isCycle(visited, n)) return dist[i];
            }
        }
        return -1;
    }

    void dfs(int node, vector<vector<int>> &graph, int visited[], int dist[])
    {
        visited[node] = 1;
        for (int child : graph[node]) {
            if (visited[child] == 0) {
                dist[child] = dist[node] + 1;
                dfs(child, graph, visited, dist);
            } else if (visited[child] == 1) {
                if (dist[node] + 1 > dist[child]) dist[child] = dist[node] + 1;
            }
        }
    }

    bool isCycle(int visited[], int n)
    {
        for (int i = 0; i < n; i++) if (visited[i] != 2) return false;
        return true;
    }
};

int main() {
    vector<vector<int>> edges = {{0, 1}, {1, 2}, {0, 2}};
    Solution obj;
    cout << obj.solve(edges) << endl;
    return 0;
}
